/* ============================================================
   STEP 4 — UPLOAD
   ============================================================ */
const UploadStep = ({ value, onChange, onNext }) => {
  const [drag, setDrag] = useState(false);
  const fileRef = useRef(null);

  const handleFile = useCallback((file) => {
    if (!file || !file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onload = (e) => onChange({ file, preview: e.target.result, name: file.name });
    reader.readAsDataURL(file);
  }, [onChange]);

  const onDrop = (e) => {
    e.preventDefault();
    setDrag(false);
    handleFile(e.dataTransfer.files[0]);
  };

  return (
    <StepLayout
      eyebrow="04 · Foto de tu mascota"
      title="Subí una foto."
      subtitle="Mejor con buena luz, fondo simple y la cara visible."
      footer={
        <PrimaryButton onClick={onNext} disabled={!value}>
          Continuar
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4">
            <path d="M5 12h14M13 6l6 6-6 6" />
          </svg>
        </PrimaryButton>
      }
    >
      <div
        onDragOver={(e) => { e.preventDefault(); setDrag(true); }}
        onDragLeave={() => setDrag(false)}
        onDrop={onDrop}
        onClick={() => fileRef.current?.click()}
        className={`relative aspect-square w-full rounded-3xl border-2 border-dashed transition-all cursor-pointer overflow-hidden ${
          drag
            ? 'border-neutral-900 bg-neutral-50 scale-[0.99]'
            : value
            ? 'border-neutral-900'
            : 'border-neutral-300 hover:border-neutral-500 bg-neutral-50'
        }`}
      >
        <input
          ref={fileRef}
          type="file"
          accept="image/*"
          className="hidden"
          onChange={(e) => handleFile(e.target.files?.[0])}
        />

        {value ? (
          <>
            <img src={value.preview} alt="Preview" className="absolute inset-0 w-full h-full object-cover" />
            <button
              type="button"
              onClick={(e) => { e.stopPropagation(); onChange(null); }}
              className="absolute top-3 right-3 bg-white/95 backdrop-blur rounded-full px-3 py-1.5 text-xs font-bold tracking-wide hover:bg-white"
            >
              Cambiar
            </button>
          </>
        ) : (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-6">
            <div className="w-14 h-14 rounded-full bg-neutral-900 flex items-center justify-center mb-4">
              <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.8">
                <path d="M12 16V4M5 11l7-7 7 7M4 20h16" />
              </svg>
            </div>
            <div className="font-bold text-base">Tocá para subir</div>
            <div className="text-xs text-neutral-500 mt-1">
              o arrastrá una imagen acá
            </div>
            <div className="text-[10px] text-neutral-400 mt-3 tracking-wide">
              JPG · PNG · HEIC · hasta 10MB
            </div>
          </div>
        )}
      </div>

      {/* Tips */}
      <div className="mt-5 space-y-2">
        {[
          { ok: true,  txt: 'Foto de cuerpo o cara enfocada' },
          { ok: true,  txt: 'Buena iluminación natural' },
          { ok: false, txt: 'Evitar filtros o fotos pixeladas' },
        ].map((tip, i) => (
          <div key={i} className="flex items-center gap-3 text-sm">
            <div className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 ${
              tip.ok ? 'bg-neutral-900' : 'bg-neutral-200'
            }`}>
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke={tip.ok ? 'white' : '#737373'} strokeWidth="3">
                {tip.ok ? <path d="M5 12l5 5 9-11" /> : <path d="M6 6l12 12M18 6L6 18" />}
              </svg>
            </div>
            <span className={tip.ok ? 'text-neutral-700' : 'text-neutral-400'}>{tip.txt}</span>
          </div>
        ))}
      </div>
    </StepLayout>
  );
};

